sql:
SELECT event_name
FROM storm_events
WHERE severity_id = 0 AND location_id = 1;

SELECT COUNT(*) AS total_fatalities_events
FROM storm_events
WHERE fatalities > 0;

SELECT event_name
FROM storm_events
WHERE economic_loss_usd = (SELECT MAX(economic_loss_usd) FROM storm_events);

external_knowledge:
- 'costliest storms' refers to those with the highest economic losses in US dollars; 
- 'top 3' means the three storms with the highest economic losses; 
- 'km/h' stands for kilometers per hour; 
- 'North Atlantic' refers to the ocean basin where the storms occurred.

sql:
SELECT event_name, economic_loss_usd
FROM storm_events
ORDER BY economic_loss_usd DESC;
